-- 4.4.1 Отдел углублённых проверок деятельности клиентов
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.4.1'
  FROM (VALUES
    ('Разработка программ и процедур, направленных на выявление и предотвращение необычных операций (сделок), выявлении совокупности подозрительных операций и (или) действий, в том числе при осуществлении Банком профессиональной деятельности на рынке ценных бумаг, которые могут привести к потере Банком своей деловой репутации или иным правовым и финансовым рискам, в части, касающейся деятельности Отдела углублённых проверок деятельности клиентов','methodology'),
    ('Осуществление выявления новых типов сомнительных финансовых схем, направленных на легализацию преступных доходов, или финансирование терроризма, в части, касающейся деятельности Отдела углублённых проверок деятельности клиентов','analytical'),
    ('Разработка технических заданий в рамках автоматизации процессов финансового мониторинга по вопросам, входящим в компетенцию Отдела углублённых проверок деятельности клиентов','methodology'),
    ('Осуществление подготовки аналитических заключений по результатам углублённой проверки клиентов для Руководителя с целью квалификации необычных операций (сделок) клиентов (обычные или подозрительные)','analytical'),
    ('Участие в процедурах по сопровождению проверок Банка России, внутреннего аудита Банка, в части подготовки и предоставления документов и сведений, относящихся к компетенции Отдела углублённых проверок деятельности клиентов','control'),
    ('Предоставление документов и сведений для подготовки ответов на обращения государственных органов (ФНС, МВД и пр.) в части компетенции Отдела углублённых проверок деятельности клиентов','communication'),
    ('Осуществление рассмотрения обращений структурных бизнес-подразделений Банка в целях минимизации риска проведения клиентами подозрительных операций (сделок) (кроме согласования индивидуальных тарифов)','control'),
    ('Обеспечение подготовки и направления в адрес клиентов ответов на их обращения, связанные с выполнением деятельности Подразделения, в части компетенции Отдела углублённых проверок деятельности клиентов','communication'),
    ('Осуществление консультирования работников УФМ СЦ по вопросам формирования сообщений о подозрительных операциях в целях обеспечения неукоснительного соблюдения ими требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','communication')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.4.1' AND u.is_archived = false;